import{_ as r,o,c as a,a2 as s}from"./chunks/framework.DnrXFDHb.js";const n="/images/%E6%96%87%E7%AB%A0-%E4%B8%80%E4%B8%AA%E6%A1%86%E6%9E%B6%E7%9C%8B%E6%87%82%E7%94%B5%E5%8A%9B%E6%96%B0%E8%83%BD%E6%BA%90-%E5%B0%81%E9%9D%A2.png",d="/images/%E6%96%87%E7%AB%A0-%E4%B8%80%E4%B8%AA%E6%A1%86%E6%9E%B6%E7%9C%8B%E6%87%82%E7%94%B5%E5%8A%9B%E6%96%B0%E8%83%BD%E6%BA%90-%E5%9B%BE1.png",e="/images/%E6%96%87%E7%AB%A0-%E4%B8%80%E4%B8%AA%E6%A1%86%E6%9E%B6%E7%9C%8B%E6%87%82%E7%94%B5%E5%8A%9B%E6%96%B0%E8%83%BD%E6%BA%90-%E5%9B%BE2.png",E="/images/%E6%96%87%E7%AB%A0-%E4%B8%80%E4%B8%AA%E6%A1%86%E6%9E%B6%E7%9C%8B%E6%87%82%E7%94%B5%E5%8A%9B%E6%96%B0%E8%83%BD%E6%BA%90-%E5%9B%BE3.png",u=JSON.parse('{"title":"一个框架看懂电力新能源赛道","description":"5分钟速读版 — 三层框架看懂电力新能源投资逻辑","frontmatter":{"title":"一个框架看懂电力新能源赛道","description":"5分钟速读版 — 三层框架看懂电力新能源投资逻辑"},"headers":[],"relativePath":"电力新能源/新赛道/一个框架看懂电力新能源赛道.md","filePath":"电力新能源/新赛道/一个框架看懂电力新能源赛道.md","lastUpdated":1781621873000}'),l={name:"电力新能源/新赛道/一个框架看懂电力新能源赛道.md"};function p(i,t,g,B,h,_){return o(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="一个框架看懂电力新能源赛道-5-分钟速读版" tabindex="-1">一个框架看懂电力新能源赛道（5 分钟速读版） <a class="header-anchor" href="#一个框架看懂电力新能源赛道-5-分钟速读版" aria-label="Permalink to &quot;一个框架看懂电力新能源赛道（5 分钟速读版）&quot;">​</a></h1><p><strong>适合谁读：</strong> 刚入行或跨赛道的投资人、正在融资的能源科技创业者、想系统性了解这个赛道的所有人 <strong>阅读时间：</strong> 5 分钟</p><p><img src="'+n+'" alt="一个框架看懂电力新能源赛道 - 封面图"></p><p>任何一个电力新能源项目，都可以放进这三层里的某一层。投什么、怎么投、投多大，跟它所在的层级直接相关。</p><h2 id="l1-发电层-供给端" tabindex="-1">L1 发电层：供给端 <a class="header-anchor" href="#l1-发电层-供给端" aria-label="Permalink to &quot;L1 发电层：供给端&quot;">​</a></h2><p><strong>投什么：</strong> 光伏制造、风电整机、电化学储能、钠离子电池、氢能、核聚变（早期）</p><p><strong>投资逻辑：</strong> 这是一个&quot;制造业逻辑&quot;的赛道——规模效应、成本曲线、产能利用率是核心指标。谁的成本更低、良率更高、扩产更快，谁就赢。</p><p><strong>当前阶段：</strong> 光伏和锂电已经进入红海，头部格局基本锁定，PE 窗口在关闭。钠电正在拐点期——2026 年是量产元年，但技术路线还没收敛（层状氧化物 vs 聚阴离子，押哪条？）。氢能和核聚变还在早期，VC 阶段。</p><p><strong>关键词：</strong> 成本曲线、产能过剩、技术路线收敛、IRR 15-25%</p><p><img src="'+d+'" alt="L1 发电层 - 示意图"></p><hr><h2 id="l2-输配层-管道" tabindex="-1">L2 输配层：管道 <a class="header-anchor" href="#l2-输配层-管道" aria-label="Permalink to &quot;L2 输配层：管道&quot;">​</a></h2><p><strong>投什么：</strong> 特高压设备、配电自动化、虚拟电厂平台、电力交易软件</p><p><strong>投资逻辑：</strong> 这是&quot;基础设施逻辑&quot;——收入模型更像 toll road（收费公路）。资产重、回报稳、周期长、政策依赖度高。</p><p><strong>当前阶段：</strong> 特高压建设是确定性最高的方向，但投资窗口基本在央企体系内，市场化 PE 参与空间有限。虚拟电厂（VPP）是新兴赛道，政策在推动，但商业模式还在验证期。</p><p><strong>关键词：</strong> 政策驱动、资产重、IRR 10-20%、退出靠 IPO 或央企收购</p><p><img src="'+e+'" alt="L2 输配层 - 示意图"></p><hr><h2 id="l3-消费层-需求端" tabindex="-1">L3 消费层：需求端 <a class="header-anchor" href="#l3-消费层-需求端" aria-label="Permalink to &quot;L3 消费层：需求端&quot;">​</a></h2><p><strong>投什么：</strong> AI 数据中心、液冷系统、电动车充电网络、算电协同平台</p><p><strong>投资逻辑：</strong> 这是&quot;服务/软件逻辑&quot;——轻资产、高增长、客户粘性是核心。谁能让客户离不开他，谁就值得更高的估值。</p><p><strong>当前阶段：</strong> AI 数据中心是 2026 年最大的投资主题之一。算力需求三年翻三倍，电力成为瓶颈。围绕数据中心的配套——液冷、备用电源、绿电采购——都在快速增长。算电协同（&quot;算随电动&quot;）是更新的概念，国内首单刚落地，距离规模化还有距离。</p><p><strong>关键词：</strong> 高增长、轻资产、客户黏性、IRR 25-35%</p><p><img src="'+E+'" alt="L3 消费层 - 示意图"></p><hr><h2 id="三层怎么投-一个决策框架" tabindex="-1">三层怎么投？一个决策框架 <a class="header-anchor" href="#三层怎么投-一个决策框架" aria-label="Permalink to &quot;三层怎么投？一个决策框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>L1 发电层</th><th>L2 输配层</th><th>L3 消费层</th></tr></thead><tbody><tr><td>确定性</td><td>⭐⭐ (技术路线风险)</td><td>⭐⭐⭐⭐ (政策推动)</td><td>⭐⭐⭐⭐⭐ (需求确定)</td></tr><tr><td>弹性</td><td>⭐⭐⭐⭐ (成本下降空间)</td><td>⭐⭐ (回报天花板低)</td><td>⭐⭐⭐⭐ (高增长)</td></tr><tr><td>PE 窗口</td><td>🟡 钠电/氢能</td><td>🟢 虚拟电厂</td><td>🟢 液冷/算电协同</td></tr><tr><td>退出路径</td><td>IPO/并购</td><td>央企收购/IPO</td><td>IPO/战略收购</td></tr><tr><td>适合谁</td><td>能承受技术风险</td><td>追求稳健回报</td><td>追求高增长</td></tr></tbody></table><p><strong>简单结论：</strong></p><ul><li>如果你想投确定性最高的 → <strong>L3 消费层</strong>（AI 数据中心配套）</li><li>如果你想投弹性最大的 → <strong>L1 发电层</strong>（钠电，但要赌对技术路线）</li><li>如果你想投最稳的 → <strong>L2 输配层</strong>（虚拟电厂，但要等政策）</li></ul><hr><h2 id="三个提醒" tabindex="-1">三个提醒 <a class="header-anchor" href="#三个提醒" aria-label="Permalink to &quot;三个提醒&quot;">​</a></h2><ol><li><p><strong>不要被&quot;新能源&quot;三个字迷惑。</strong> 光伏、锂电、钠电、氢能、虚拟电厂、液冷——它们是完全不同的生意逻辑。有的是制造业（看成本），有的是基础设施（看政策），有的是服务业（看客户黏性）。</p></li><li><p><strong>关注&quot;谁在买单&quot;。</strong> 新能源行业最大的特点是：买单一大部分不是市场化的。电网公司、地方政府、央企——它们的决策逻辑和纯市场化客户完全不同。理解买单方的动机，比分析技术本身更重要。</p></li><li><p><strong>PE 和 VC 要分的赛道上限不同。</strong> 光伏制造已经不适合 PE 了（格局锁定），但液冷系统正处在 PE 的甜蜜点（放量早期，格局未定）。知道你投的是什么阶段，比知道&quot;赛道好不好&quot;更重要。</p></li></ol><hr><blockquote><p><strong>📢 免责声明：</strong> 本文仅为投资研究框架分享，不构成任何投资建议。</p></blockquote>',34)])])}const A=r(l,[["render",p]]);export{u as __pageData,A as default};
